output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?tax ?taxLabel WHERE {
  VALUES ?tax {
    wd:Q1308197 wd:Q3149559 wd:Q780044
  }
  ?tax rdfs:label ?taxLabel .
  FILTER(LANG(?taxLabel) = "en")
}
LIMIT 1

